@inject Services.ISettingsService SettingsService

<h4 class="mb-4">Profile</h4>

@if (_loading)
{
    <p class="text-muted">Loading profile…</p>
}
else
{
    @if (!string.IsNullOrEmpty(_message))
    {
        <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible py-2">
            @_message
            <button type="button" class="btn-close" @onclick="() => _message = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="_displayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="_email" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="_bio"></textarea>
            </div>
        </div>

        <div class="col-md-4 text-center">
            <div class="mb-2">
                <img src="@_avatarUrl" alt="Avatar" class="rounded-circle"
                     style="width:120px;height:120px;object-fit:cover;"
                     @onerror="@(() => {})" />
            </div>
            <div class="small text-muted text-break">@_avatarUrl</div>
        </div>
    </div>

    <div class="d-flex gap-2 mt-3">
        <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
            @(_saving ? "Saving…" : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
    </div>
}

@code {
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    // Last-saved state for discard
    private Models.UserProfile? _savedProfile;

    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _messageIsError;

    protected override async Task OnInitializedAsync()
    {
        var profile = await SettingsService.GetProfileAsync();
        _savedProfile = profile;
        ApplyProfile(profile);
        _loading = false;
    }

    private void ApplyProfile(Models.UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _avatarUrl = p.AvatarUrl;
        _bio = p.Bio;
    }

    private async Task Save()
    {
        _saving = true;
        _message = null;
        try
        {
            var profile = new Models.UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(profile);
            _savedProfile = profile;
            _message = "Profile saved successfully!";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Error saving profile: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
            _message = null;
        }
    }
}

@inject Services.ISettingsService SettingsService

<h4 class="mb-4">Notifications</h4>

@if (_loading)
{
    <p class="text-muted">Loading preferences…</p>
}
else
{
    @if (!string.IsNullOrEmpty(_message))
    {
        <div class="alert alert-success alert-dismissible py-2">
            @_message
            <button type="button" class="btn-close" @onclick="() => _message = null"></button>
        </div>
    }

    <div class="mb-4">
        <h6>Notification Channels</h6>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <div class="mb-4">
        <h6>Muted Channels</h6>
        <p class="text-muted small">Uncheck channels you want to receive notifications from.</p>
        @foreach (var channel in _channels)
        {
            <div class="form-check mb-1">
                <input class="form-check-input" type="checkbox" id="@($"ch-{channel.Name}")"
                       checked="@channel.Muted"
                       @onchange="e => channel.Muted = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="@($"ch-{channel.Name}")">
                    #@channel.Name
                </label>
            </div>
        }
    </div>

    <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
        @(_saving ? "Saving…" : "Save Preferences")
    </button>
}

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<ChannelState> _channels = new();

    private bool _loading = true;
    private bool _saving;
    private string? _message;

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _channels = prefs.MutedChannels
            .Select(c => new ChannelState { Name = c, Muted = true })
            .ToList();
        _loading = false;
    }

    private async Task Save()
    {
        _saving = true;
        _message = null;
        var mutedChannels = _channels.Where(c => c.Muted).Select(c => c.Name).ToList();
        var prefs = new Models.NotificationPrefs(
            _emailNotifications, _pushNotifications, _weeklyDigest, mutedChannels);
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _message = "Notification preferences saved!";
        _saving = false;
    }

    private class ChannelState
    {
        public string Name { get; set; } = "";
        public bool Muted { get; set; }
    }
}

@using sv_4cd20704be32440ca32d750cd2d10262.Models
@inject Services.ISettingsService SettingsService

<h4 class="mb-4">Security</h4>

@if (_loading)
{
    <p class="text-muted">Loading security settings…</p>
}
else
{
    <div class="mb-4">
        <ChangePasswordPanel OnChangePassword="HandlePasswordChange" />
    </div>

    <div class="mb-4">
        <h6>Two-Factor Authentication</h6>
        <div class="d-flex align-items-center gap-3">
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="twoFactor"
                       checked="@_twoFactorEnabled" disabled />
                <label class="form-check-label" for="twoFactor">
                    @(_twoFactorEnabled ? "Enabled" : "Disabled")
                </label>
            </div>
            <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-warning")">
                @(_twoFactorEnabled ? "✓ Active" : "⚠ Inactive")
            </span>
        </div>
        @if (_lastPasswordChange.HasValue)
        {
            <p class="text-muted small mt-2">
                Last password change: @_lastPasswordChange.Value.ToString("MMMM d, yyyy")
            </p>
        }
    </div>

    <div class="mb-4">
        <ActiveSessionsTable Sessions="_sessions"
                             CurrentSessionId="sess-1"
                             OnRevokeRequested="ShowRevokeDialog" />
    </div>

    <RevokeSessionDialog Visible="_showRevokeDialog"
                         Session="_sessionToRevoke"
                         OnConfirm="ConfirmRevoke"
                         OnCancel="CancelRevoke" />
}

@code {
    private bool _loading = true;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = new();

    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions;
        _loading = false;
    }

    private async Task HandlePasswordChange((string current, string newPwd) args)
    {
        await SettingsService.ChangePasswordAsync(args.current, args.newPwd);
        _lastPasswordChange = DateTime.UtcNow;
    }

    private void ShowRevokeDialog(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _sessions = _sessions.Where(s => s.Id != _sessionToRevoke.Id).ToList();
        }
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }
}

@inject Services.ISettingsService SettingsService

<h4 class="mb-4">Appearance</h4>

@if (_loading)
{
    <p class="text-muted">Loading appearance settings…</p>
}
else
{
    @if (!string.IsNullOrEmpty(_message))
    {
        <div class="alert alert-success alert-dismissible py-2">
            @_message
            <button type="button" class="btn-close" @onclick="() => _message = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-6">
            <div class="mb-4">
                <h6>Theme</h6>
                @foreach (var theme in new[] { "Light", "Dark", "System" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme"
                               id="@($"theme-{theme}")" value="@theme"
                               checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6>Font Size</h6>
                @foreach (var size in new[] { "Small", "Medium", "Large" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize"
                               id="@($"fs-{size}")" value="@size"
                               checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6>Language</h6>
                <select class="form-select" @bind="_language">
                    <option value="English">English</option>
                    <option value="Spanish">Spanish</option>
                    <option value="French">French</option>
                    <option value="German">German</option>
                    <option value="Japanese">Japanese</option>
                    <option value="Chinese">Chinese</option>
                </select>
            </div>

            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
                @(_saving ? "Saving…" : "Save")
            </button>
        </div>

        <div class="col-md-6">
            <h6>Live Preview</h6>
            <div class="border rounded p-3 @PreviewBgClass" style="@PreviewStyle">
                <div class="d-flex justify-content-between align-items-center mb-2"
                     style="border-bottom: 1px solid @PreviewBorderColor;">
                    <strong style="color: @PreviewTextColor;">Settings Dashboard</strong>
                    <span class="badge" style="background-color: @PreviewAccentColor;">@_theme</span>
                </div>
                <p class="mb-1" style="color: @PreviewTextColor;">
                    This is a preview of your selected appearance.
                </p>
                <p class="@(_compactMode ? "mb-0 small" : "mb-2")" style="color: @PreviewMutedColor;">
                    Font size: @_fontSize · Language: @_language · Compact: @(_compactMode ? "On" : "Off")
                </p>
                <div class="d-flex gap-2 @(_compactMode ? "" : "mt-3")">
                    <button class="btn btn-sm" style="background-color: @PreviewAccentColor; color: white;">
                        Primary
                    </button>
                    <button class="btn btn-sm btn-outline-secondary">Secondary</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private bool _loading = true;
    private bool _saving;
    private string? _message;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task Save()
    {
        _saving = true;
        _message = null;
        var settings = new Models.AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _message = "Appearance settings saved!";
        _saving = false;
    }

    private string PreviewStyle => $"font-size: {FontSizeCss}; background-color: {PreviewBgColor}; transition: all 0.3s;";
    private string PreviewBgClass => "";
