<h4 class="mb-4">Appearance</h4>

@if (_loading)
{
    <p class="text-muted">Loading appearance settings…</p>
}
else
{
    @if (!string.IsNullOrEmpty(_message))
    {
        <div class="alert alert-success alert-dismissible py-2">
            @_message
            <button type="button" class="btn-close" @onclick="() => _message = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-6">
            <div class="mb-4">
                <h6>Theme</h6>
                @foreach (var theme in new[] { "Light", "Dark", "System" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme"
                               id="@($"theme-{theme}")" value="@theme"
                               checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6>Font Size</h6>
                @foreach (var size in new[] { "Small", "Medium", "Large" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize"
                               id="@($"fs-{size}")" value="@size"
                               checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6>Language</h6>
                <select class="form-select" @bind="_language">
                    <option value="English">English</option>
                    <option value="Spanish">Spanish</option>
                    <option value="French">French</option>
                    <option value="German">German</option>
                    <option value="Japanese">Japanese</option>
                    <option value="Chinese">Chinese</option>
                </select>
            </div>

            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
                @(_saving ? "Saving…" : "Save")
            </button>
        </div>

        <div class="col-md-6">
            <h6>Live Preview</h6>
            <div class="border rounded p-3 @PreviewBgClass" style="@PreviewStyle">
                <div class="d-flex justify-content-between align-items-center mb-2"
                     style="border-bottom: 1px solid @PreviewBorderColor;">
                    <strong style="color: @PreviewTextColor;">Settings Dashboard</strong>
                    <span class="badge" style="background-color: @PreviewAccentColor;">@_theme</span>
                </div>
                <p class="mb-1" style="color: @PreviewTextColor;">
                    This is a preview of your selected appearance.
                </p>
                <p class="@(_compactMode ? "mb-0 small" : "mb-2")" style="color: @PreviewMutedColor;">
                    Font size: @_fontSize · Language: @_language · Compact: @(_compactMode ? "On" : "Off")
                </p>
                <div class="d-flex gap-2 @(_compactMode ? "" : "mt-3")">
                    <button class="btn btn-sm" style="background-color: @PreviewAccentColor; color: white;">
                        Primary
                    </button>
                    <button class="btn btn-sm btn-outline-secondary">Secondary</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private bool _loading = true;
    private bool _saving;
    private string? _message;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task Save()
    {
        _saving = true;
        _message = null;
        var settings = new Models.AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _message = "Appearance settings saved!";
        _saving = false;
    }

    private string PreviewStyle => $"font-size: {FontSizeCss}; background-color: {PreviewBgColor}; transition: all 0.3s;";
    private string PreviewBgClass => "";
    private string PreviewBgColor => _theme == "Dark" ? "#1e1e2e" : "#ffffff";
    private string PreviewTextColor => _theme == "Dark" ? "#cdd6f4" : "#212529";
    private string PreviewMutedColor => _theme == "Dark" ? "#6c7086" : "#6c757d";
    private string PreviewBorderColor => _theme == "Dark" ? "#45475a" : "#dee2e6";
    private string PreviewAccentColor => _theme == "Dark" ? "#89b4fa" : "#0d6efd";

    private string FontSizeCss => _fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };
}
