@inject Services.ISettingsService SettingsService

<h4 class="mb-4">Notifications</h4>

@if (_loading)
{
    <p class="text-muted">Loading preferences…</p>
}
else
{
    @if (!string.IsNullOrEmpty(_message))
    {
        <div class="alert alert-success alert-dismissible py-2">
            @_message
            <button type="button" class="btn-close" @onclick="() => _message = null"></button>
        </div>
    }

    <div class="mb-4">
        <h6>Notification Channels</h6>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <div class="mb-4">
        <h6>Muted Channels</h6>
        <p class="text-muted small">Uncheck channels you want to receive notifications from.</p>
        @foreach (var channel in _channels)
        {
            <div class="form-check mb-1">
                <input class="form-check-input" type="checkbox" id="@($"ch-{channel.Name}")"
                       checked="@channel.Muted"
                       @onchange="e => channel.Muted = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="@($"ch-{channel.Name}")">
                    #@channel.Name
                </label>
            </div>
        }
    </div>

    <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
        @(_saving ? "Saving…" : "Save Preferences")
    </button>
}

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<ChannelState> _channels = new();

    private bool _loading = true;
    private bool _saving;
    private string? _message;

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _channels = prefs.MutedChannels
            .Select(c => new ChannelState { Name = c, Muted = true })
            .ToList();
        _loading = false;
    }

    private async Task Save()
    {
        _saving = true;
        _message = null;
        var mutedChannels = _channels.Where(c => c.Muted).Select(c => c.Name).ToList();
        var prefs = new Models.NotificationPrefs(
            _emailNotifications, _pushNotifications, _weeklyDigest, mutedChannels);
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _message = "Notification preferences saved!";
        _saving = false;
    }

    private class ChannelState
    {
        public string Name { get; set; } = "";
        public bool Muted { get; set; }
    }
}

